// src/main/kotlin/com/helios/payment/consumer/PaymentCompletedConsumer.kt

package com.helios.payment.consumer

import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.launch
import org.apache.kafka.clients.consumer.ConsumerConfig
import org.apache.kafka.clients.consumer.KafkaConsumer
import org.apache.kafka.common.serialization.StringDeserializer
import org.slf4j.LoggerFactory
import org.slf4j.MDC
import java.time.Duration
import java.util.Properties

class PaymentCompletedConsumer(
    private val bootstrapServers: String,
    private val groupId: String = "payment-completed-consumer",
    private val handler: suspend (PaymentCompletedEvent) -> Unit,
) {
    private val log = LoggerFactory.getLogger(javaClass)
    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())

    private val consumer = KafkaConsumer<String, String>(Properties().apply {
        put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers)
        put(ConsumerConfig.GROUP_ID_CONFIG, groupId)
        put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer::class.java.name)
        put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer::class.java.name)
        put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest")
        put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "false")
    })

    fun start() {
        consumer.subscribe(listOf(TOPIC))
        log.info("Subscribed to topic={}", TOPIC)

        scope.launch {
            while (true) {
                val records = consumer.poll(Duration.ofMillis(500))
                for (record in records) {
                    val correlationId = extractCorrelationId(record.headers())
                    MDC.put("correlationId", correlationId)
                    MDC.put("topic", TOPIC)
                    MDC.put("partition", record.partition().toString())
                    MDC.put("offset", record.offset().toString())

                    try {
                        val event = deserialize(record.value())
                        log.info("Processing payment_completed paymentId={}", event.paymentId)
                        handler(event)
                        consumer.commitSync()
                    } catch (e: Exception) {
                        log.error("Failed to process record offset={}", record.offset(), e)
                        // TODO: dead-letter queue or retry policy
                    } finally {
                        MDC.clear()
                    }
                }
            }
        }
    }

    fun stop() {
        consumer.close()
    }

    private fun extractCorrelationId(headers: org.apache.kafka.common.header.Headers): String =
        headers.lastHeader("correlationId")?.value()?.let { String(it) }
            ?: java.util.UUID.randomUUID().toString()

    private fun deserialize(json: String): PaymentCompletedEvent =
        // swap in your ObjectMapper / kotlinx.serialization
        com.fasterxml.jackson.module.kotlin.jacksonObjectMapper()
            .readValue(json, PaymentCompletedEvent::class.java)

    companion object {
        const val TOPIC = "payment.completed"
    }
}
