package com.helios.payment.consumer

import kotlinx.coroutines.CompletableDeferred
import kotlinx.coroutines.runBlocking
import kotlinx.coroutines.withTimeout
import org.apache.kafka.clients.producer.KafkaProducer
import org.apache.kafka.clients.producer.ProducerConfig
import org.apache.kafka.clients.producer.ProducerRecord
import org.apache.kafka.common.serialization.StringSerializer
import org.junit.jupiter.api.AfterAll
import org.junit.jupiter.api.Assertions.assertEquals
import org.junit.jupiter.api.BeforeAll
import org.junit.jupiter.api.Test
import org.testcontainers.kafka.KafkaContainer
import java.math.BigDecimal
import java.time.Instant
import java.util.Properties
import java.util.UUID

class PaymentCompletedConsumerIT {

    companion object {
        private val kafka = KafkaContainer("apache/kafka:3.7.0")

        @BeforeAll @JvmStatic fun setUp() { kafka.start() }
        @AfterAll  @JvmStatic fun tearDown() { kafka.stop() }
    }

    @Test
    fun `consumes payment-completed event and invokes handler`() = runBlocking {
        val received = CompletableDeferred<PaymentCompletedEvent>()

        val consumer = PaymentCompletedConsumer(
            bootstrapServers = kafka.bootstrapServers,
            handler = { received.complete(it) },
        )
        consumer.start()

        val event = PaymentCompletedEvent(
            paymentId = UUID.randomUUID(),
            accountId = UUID.randomUUID(),
            amount = BigDecimal("150.00"),
            currency = "USD",
            completedAt = Instant.now(),
            correlationId = UUID.randomUUID().toString(),
        )
        publishEvent(event)

        val result = withTimeout(10_000) { received.await() }
        assertEquals(event.paymentId, result.paymentId)
        assertEquals(event.amount, result.amount)

        consumer.stop()
    }

    private fun publishEvent(event: PaymentCompletedEvent) {
        val producer = KafkaProducer<String, String>(Properties().apply {
            put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, kafka.bootstrapServers)
            put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer::class.java.name)
            put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer::class.java.name)
        })
        val json = com.fasterxml.jackson.module.kotlin.jacksonObjectMapper()
            .writeValueAsString(event)
        producer.send(ProducerRecord(PaymentCompletedConsumer.TOPIC, event.paymentId.toString(), json)).get()
        producer.close()
    }
}
